#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void bpnn_layerforward_ocl(
    __global float *l1,
    __global float *l2,
    __global float *conn,
    __global float *partial_sum,
    __local float *local_conn,
    __local float *local_l1,
    int n1,
    int n2)
{
    int j = get_global_id(1);
    int k_block = get_global_id(0);
    int local_id = get_local_id(0);

    if (j >= n2 || j == 0) return;

    float sum = 0.0f;

    int n1_blocks = (n1 + 1) / BLOCK_SIZE;
    if (k_block >= n1_blocks) return;

    int k_start = k_block * BLOCK_SIZE;
    int k_end = k_start + BLOCK_SIZE;
    if (k_end > n1 + 1) k_end = n1 + 1;

    for (int k = k_start; k < k_end; k++) {
        float weight = conn[k * (n2 + 1) + j];
        float input_val = (k == 0) ? 1.0f : l1[k];
        sum += weight * input_val;
    }

    partial_sum[k_block * n2 + (j - 1)] = sum;
}

__kernel void bpnn_adjust_weights_ocl(
    __global float *delta,
    int ndelta,
    __global float *ly,
    int nly,
    __global float *w,
    __global float *oldw)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j < 1 || j > ndelta) return;
    if (k > nly) return;

    float delta_val = delta[j];
    float ly_val = (k == 0) ? 1.0f : ly[k];

    float new_dw = (0.3f * delta_val * ly_val) + (0.3f * oldw[k * (ndelta + 1) + j]);

    w[k * (ndelta + 1) + j] += new_dw;
    oldw[k * (ndelta + 1) + j] = new_dw;
}
